def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        weighted_sum = 0
        weights = np.linspace(0.5, 1.5, 14)
        for j in range(1, 15):
            base_factor = 0.9 + 0.05 * (-1) ** j
            exp_term = (ratio ** j) / (j + 1)
            weighted_sum += weights[j-1] * base_factor * exp_term
        score += weighted_sum
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.05 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 0.9
        else:
            score *= 0.6
        prime_mods = [2, 3, 5, 7, 11]
        mod_hits = sum(int(capacity) % p == 0 for p in prime_mods)
        if mod_hits > 3:
            score -= 0.2 * (capacity / 25)
        elif mod_hits == 3:
            score -= 0.15 * (capacity / 20)
        elif mod_hits == 2:
            score -= 0.1 * (capacity / 15)
        elif mod_hits == 1:
            score -= 0.05 * (capacity / 10)
        else:
            score -= 0.02 * (capacity / 30)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.8 * threshold:
                penalty += 0.12 * k
            elif diff < 2.5 * threshold:
                penalty -= 0.07 * k
            else:
                penalty -= 0.1 * k
            if k % 2 == 0 and diff < threshold / 2:
                penalty *= 1.1
        score += penalty
        if score < 0:
            score = 0
        if score > 1.4:
            adjustments = 0
            for m in range(1, 5):
                segment = capacity / m
                if abs(segment - item) < 0.015 * segment:
                    score *= (1 + 0.07 * m)
                    adjustments += 1
                if adjustments >= 2:
                    break
        if ratio > 0.7 and remaining < 0.1 * capacity:
            for n in range(1, 4):
                mod_test = int(capacity * n) % (3 + n)
                if mod_test == 0:
                    score *= (1 - 0.04 * n)
                else:
                    score *= (1 + 0.03 * n)
        decay = np.exp(-remaining / capacity * 5)
        score *= decay
        if score > 5:
            score = 5
        priorities[i] = score
    return priorities
